contracts/AppointmentRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title AppointmentRegistry
 * @dev Manages immutable appointment records with status tracking and audit trail
 */
contract AppointmentRegistry is AccessControl, ReentrancyGuard {
    bytes32 public constant DOCTOR_ROLE = keccak256("DOCTOR_ROLE");
    bytes32 public constant PATIENT_ROLE = keccak256("PATIENT_ROLE");
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    
    enum AppointmentStatus {
        SCHEDULED,
        CONFIRMED,
        COMPLETED,
        CANCELLED,
        NO_SHOW,
        RESCHEDULED
    }
    
    struct Appointment {
        bytes32 appointmentHash;
        address patient;
        address doctor;
        uint256 appointmentDate;
        string appointmentType;
        AppointmentStatus status;
        uint256 createdAt;
        uint256 lastUpdatedAt;
        uint256 completedAt;
        uint256 cancelledAt;
        string ipfsHash;
        bool isActive;
    }
    
    struct StatusChange {
        AppointmentStatus fromStatus;
        AppointmentStatus toStatus;
        uint256 timestamp;
        address changedBy;
        string reason;
    }
    
    struct RescheduleInfo {
        uint256 originalDate;
        uint256 newDate;
        uint256 timestamp;
        string reason;
        address rescheduledBy;
    }
    
    // Mappings
    mapping(uint256 => Appointment) public appointments;
    mapping(bytes32 => uint256) public appointmentHashToId;
    mapping(uint256 => StatusChange[]) public appointmentHistory;
    mapping(uint256 => RescheduleInfo[]) public rescheduleHistory;
    mapping(address => uint256[]) public patientAppointments;
    mapping(address => uint256[]) public doctorAppointments;
    
    uint256 public appointmentCount;
    
    // Events
    event AppointmentRegistered(
        uint256 indexed appointmentId,
        bytes32 indexed appointmentHash,
        address indexed patient,
        address doctor,
        uint256 appointmentDate,
        string appointmentType
    );
    
    event AppointmentStatusUpdated(
        uint256 indexed appointmentId,
        AppointmentStatus oldStatus,
        AppointmentStatus newStatus,
        address updatedBy,
        uint256 timestamp
    );
    
    event AppointmentCompleted(
        uint256 indexed appointmentId,
        address indexed doctor,
        uint256 completedAt,
        string ipfsHash
    );
    
    event AppointmentCancelled(
        uint256 indexed appointmentId,
        address cancelledBy,
        string reason,
        uint256 cancelledAt
    );
    
    event AppointmentRescheduled(
        uint256 indexed appointmentId,
        uint256 oldDate,
        uint256 newDate,
        string reason,
        address rescheduledBy
    );
    
    event NoShowMarked(
        uint256 indexed appointmentId,
        address indexed patient,
        uint256 timestamp
    );
    
    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
    }
    
    /**
     * @dev Register a new appointment on blockchain
     */
    function registerAppointment(
        bytes32 _appointmentHash,
        address _patient,
        address _doctor,
        uint256 _appointmentDate,
        string memory _appointmentType
    ) external nonReentrant returns (uint256) {
        require(_appointmentHash != bytes32(0), "Invalid appointment hash");
        require(_patient != address(0), "Invalid patient address");
        require(_doctor != address(0), "Invalid doctor address");
        require(_appointmentDate > block.timestamp, "Appointment date must be in future");
        require(appointmentHashToId[_appointmentHash] == 0, "Appointment already exists");
        
        appointmentCount++;
        uint256 appointmentId = appointmentCount;
        
        appointments[appointmentId] = Appointment({
            appointmentHash: _appointmentHash,
            patient: _patient,
            doctor: _doctor,
            appointmentDate: _appointmentDate,
            appointmentType: _appointmentType,
            status: AppointmentStatus.SCHEDULED,
            createdAt: block.timestamp,
            lastUpdatedAt: block.timestamp,
            completedAt: 0,
            cancelledAt: 0,
            ipfsHash: "",
            isActive: true
        });
        
        appointmentHashToId[_appointmentHash] = appointmentId;
        patientAppointments[_patient].push(appointmentId);
        doctorAppointments[_doctor].push(appointmentId);
        
        // Record initial status
        appointmentHistory[appointmentId].push(StatusChange({
            fromStatus: AppointmentStatus.SCHEDULED,
            toStatus: AppointmentStatus.SCHEDULED,
            timestamp: block.timestamp,
            changedBy: msg.sender,
            reason: "Initial registration"
        }));
        
        emit AppointmentRegistered(
            appointmentId,
            _appointmentHash,
            _patient,
            _doctor,
            _appointmentDate,
            _appointmentType
        );
        
        return appointmentId;
    }
    
    /**
     * @dev Update appointment status
     */
    function updateAppointmentStatus(
        uint256 _appointmentId,
        AppointmentStatus _newStatus,
        string memory _reason
    ) external nonReentrant {
        require(_appointmentId > 0 && _appointmentId <= appointmentCount, "Invalid appointment ID");
        Appointment storage appointment = appointments[_appointmentId];
        require(appointment.isActive, "Appointment is not active");
        require(
            msg.sender == appointment.doctor || 
            msg.sender == appointment.patient ||
            hasRole(ADMIN_ROLE, msg.sender),
            "Unauthorized"
        );
        
        AppointmentStatus oldStatus = appointment.status;
        appointment.status = _newStatus;
        appointment.lastUpdatedAt = block.timestamp;
        
        // Record status change
        appointmentHistory[_appointmentId].push(StatusChange({
            fromStatus: oldStatus,
            toStatus: _newStatus,
            timestamp: block.timestamp,
            changedBy: msg.sender,
            reason: _reason
        }));
        
        emit AppointmentStatusUpdated(
            _appointmentId,
            oldStatus,
            _newStatus,
            msg.sender,
            block.timestamp
        );
    }
    
    /**
     * @dev Complete an appointment
     */
    function completeAppointment(
        uint256 _appointmentId,
        string memory _ipfsHash
    ) external nonReentrant {
        require(_appointmentId > 0 && _appointmentId <= appointmentCount, "Invalid appointment ID");
        Appointment storage appointment = appointments[_appointmentId];
        require(appointment.isActive, "Appointment is not active");
        require(
            msg.sender == appointment.doctor || hasRole(ADMIN_ROLE, msg.sender),
            "Only doctor can complete appointment"
        );
        require(
            appointment.status != AppointmentStatus.COMPLETED,
            "Appointment already completed"
        );
        
        AppointmentStatus oldStatus = appointment.status;
        appointment.status = AppointmentStatus.COMPLETED;
        appointment.completedAt = block.timestamp;
        appointment.lastUpdatedAt = block.timestamp;
        appointment.ipfsHash = _ipfsHash;
        
        // Record status change
        appointmentHistory[_appointmentId].push(StatusChange({
            fromStatus: oldStatus,
            toStatus: AppointmentStatus.COMPLETED,
            timestamp: block.timestamp,
            changedBy: msg.sender,
            reason: "Appointment completed"
        }));
        
        emit AppointmentCompleted(
            _appointmentId,
            msg.sender,
            block.timestamp,
            _ipfsHash
        );
    }
    
    /**
     * @dev Cancel an appointment
     */
    function cancelAppointment(
        uint256 _appointmentId,
        string memory _reason
    ) external nonReentrant {
        require(_appointmentId > 0 && _appointmentId <= appointmentCount, "Invalid appointment ID");
        Appointment storage appointment = appointments[_appointmentId];
        require(appointment.isActive, "Appointment is not active");
        require(
            msg.sender == appointment.doctor || 
            msg.sender == appointment.patient ||
            hasRole(ADMIN_ROLE, msg.sender),
            "Unauthorized"
        );
        require(
            appointment.status != AppointmentStatus.COMPLETED &&
            appointment.status != AppointmentStatus.CANCELLED,
            "Cannot cancel completed or already cancelled appointment"
        );
        
        AppointmentStatus oldStatus = appointment.status;
        appointment.status = AppointmentStatus.CANCELLED;
        appointment.cancelledAt = block.timestamp;
        appointment.lastUpdatedAt = block.timestamp;
        
        // Record status change
        appointmentHistory[_appointmentId].push(StatusChange({
            fromStatus: oldStatus,
            toStatus: AppointmentStatus.CANCELLED,
            timestamp: block.timestamp,
            changedBy: msg.sender,
            reason: _reason
        }));
        
        emit AppointmentCancelled(
            _appointmentId,
            msg.sender,
            _reason,
            block.timestamp
        );
    }
    
    /**
     * @dev Reschedule an appointment
     */
    function rescheduleAppointment(
        uint256 _appointmentId,
        uint256 _newDate,
        string memory _reason
    ) external nonReentrant {
        require(_appointmentId > 0 && _appointmentId <= appointmentCount, "Invalid appointment ID");
        Appointment storage appointment = appointments[_appointmentId];
        require(appointment.isActive, "Appointment is not active");
        require(_newDate > block.timestamp, "New date must be in future");
        require(
            msg.sender == appointment.doctor || 
            msg.sender == appointment.patient ||
            hasRole(ADMIN_ROLE, msg.sender),
            "Unauthorized"
        );
        
        uint256 oldDate = appointment.appointmentDate;
        appointment.appointmentDate = _newDate;
        appointment.lastUpdatedAt = block.timestamp;
        
        AppointmentStatus oldStatus = appointment.status;
        appointment.status = AppointmentStatus.RESCHEDULED;
        
        // Record reschedule
        rescheduleHistory[_appointmentId].push(RescheduleInfo({
            originalDate: oldDate,
            newDate: _newDate,
            timestamp: block.timestamp,
            reason: _reason,
            rescheduledBy: msg.sender
        }));
        
        // Record status change
        appointmentHistory[_appointmentId].push(StatusChange({
            fromStatus: oldStatus,
            toStatus: AppointmentStatus.RESCHEDULED,
            timestamp: block.timestamp,
            changedBy: msg.sender,
            reason: _reason
        }));
        
        emit AppointmentRescheduled(
            _appointmentId,
            oldDate,
            _newDate,
            _reason,
            msg.sender
        );
    }
    
    /**
     * @dev Mark patient as no-show
     */
    function markNoShow(uint256 _appointmentId) external nonReentrant {
        require(_appointmentId > 0 && _appointmentId <= appointmentCount, "Invalid appointment ID");
        Appointment storage appointment = appointments[_appointmentId];
        require(appointment.isActive, "Appointment is not active");
        require(
            msg.sender == appointment.doctor || hasRole(ADMIN_ROLE, msg.sender),
            "Only doctor can mark no-show"
        );
        require(
            block.timestamp > appointment.appointmentDate,
            "Cannot mark no-show before appointment time"
        );
        
        AppointmentStatus oldStatus = appointment.status;
        appointment.status = AppointmentStatus.NO_SHOW;
        appointment.lastUpdatedAt = block.timestamp;
        
        // Record status change
        appointmentHistory[_appointmentId].push(StatusChange({
            fromStatus: oldStatus,
            toStatus: AppointmentStatus.NO_SHOW,
            timestamp: block.timestamp,
            changedBy: msg.sender,
            reason: "Patient did not attend"
        }));
        
        emit NoShowMarked(
            _appointmentId,
            appointment.patient,
            block.timestamp
        );
    }
    
    /**
     * @dev Verify an appointment exists and get its status
     */
    function verifyAppointment(bytes32 _appointmentHash) 
        external 
        view 
        returns (
            bool exists,
            AppointmentStatus status,
            uint256 appointmentDate,
            uint256 createdAt,
            bool isActive
        ) 
    {
        uint256 appointmentId = appointmentHashToId[_appointmentHash];
        if (appointmentId == 0) {
            return (false, AppointmentStatus.SCHEDULED, 0, 0, false);
        }
        
        Appointment memory appointment = appointments[appointmentId];
        return (
            true,
            appointment.status,
            appointment.appointmentDate,
            appointment.createdAt,
            appointment.isActive
        );
    }
    
    /**
     * @dev Get appointment details
     */
    function getAppointment(uint256 _appointmentId)
        external
        view
        returns (
            bytes32 appointmentHash,
            address patient,
            address doctor,
            uint256 appointmentDate,
            string memory appointmentType,
            AppointmentStatus status,
            uint256 createdAt,
            string memory ipfsHash,
            bool isActive
        )
    {
        require(_appointmentId > 0 && _appointmentId <= appointmentCount, "Invalid appointment ID");
        Appointment memory appointment = appointments[_appointmentId];
        
        return (
            appointment.appointmentHash,
            appointment.patient,
            appointment.doctor,
            appointment.appointmentDate,
            appointment.appointmentType,
            appointment.status,
            appointment.createdAt,
            appointment.ipfsHash,
            appointment.isActive
        );
    }
    
    /**
     * @dev Get appointment status history
     */
    function getAppointmentHistory(uint256 _appointmentId)
        external
        view
        returns (StatusChange[] memory)
    {
        require(_appointmentId > 0 && _appointmentId <= appointmentCount, "Invalid appointment ID");
        return appointmentHistory[_appointmentId];
    }
    
    /**
     * @dev Get reschedule history
     */
    function getRescheduleHistory(uint256 _appointmentId)
        external
        view
        returns (RescheduleInfo[] memory)
    {
        require(_appointmentId > 0 && _appointmentId <= appointmentCount, "Invalid appointment ID");
        return rescheduleHistory[_appointmentId];
    }
    
    /**
     * @dev Get patient's appointments
     */
    function getPatientAppointments(address _patient)
        external
        view
        returns (uint256[] memory)
    {
        require(
            msg.sender == _patient || hasRole(ADMIN_ROLE, msg.sender),
            "Unauthorized"
        );
        return patientAppointments[_patient];
    }
    
    /**
     * @dev Get doctor's appointments
     */
    function getDoctorAppointments(address _doctor)
        external
        view
        returns (uint256[] memory)
    {
        require(
            msg.sender == _doctor || hasRole(ADMIN_ROLE, msg.sender),
            "Unauthorized"
        );
        return doctorAppointments[_doctor];
    }
    
    /**
     * @dev Check if patient attended appointment
     */
    function didPatientAttend(uint256 _appointmentId)
        external
        view
        returns (bool attended)
    {
        require(_appointmentId > 0 && _appointmentId <= appointmentCount, "Invalid appointment ID");
        Appointment memory appointment = appointments[_appointmentId];
        
        return appointment.status == AppointmentStatus.COMPLETED;
    }
    
    /**
     * @dev Get patient attendance rate
     */
    function getPatientAttendanceRate(address _patient)
        external
        view
        returns (uint256 totalAppointments, uint256 attended, uint256 noShows)
    {
        uint256[] memory appointmentIds = patientAppointments[_patient];
        totalAppointments = appointmentIds.length;
        attended = 0;
        noShows = 0;
        
        for (uint256 i = 0; i < appointmentIds.length; i++) {
            Appointment memory appointment = appointments[appointmentIds[i]];
            if (appointment.status == AppointmentStatus.COMPLETED) {
                attended++;
            } else if (appointment.status == AppointmentStatus.NO_SHOW) {
                noShows++;
            }
        }
        
        return (totalAppointments, attended, noShows);
    }
}

contracts/ConsentManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title ConsentManager
 * @dev Manages patient consent for data sharing with healthcare providers
 */
contract ConsentManager is AccessControl {
    bytes32 public constant PATIENT_ROLE = keccak256("PATIENT_ROLE");
    
    struct Consent {
        address provider;
        string[] dataTypes;
        uint256 grantedAt;
        uint256 expiryTime;
        bool isActive;
        string purpose;
    }
    
    // patient => provider => Consent
    mapping(address => mapping(address => Consent)) public consents;
    
    // patient => providers[]
    mapping(address => address[]) public patientProviders;
    
    // Audit log
    struct ConsentLog {
        address patient;
        address provider;
        string action; // "granted", "revoked", "expired"
        uint256 timestamp;
    }
    
    ConsentLog[] public auditLog;
    
    event ConsentGranted(
        address indexed patient,
        address indexed provider,
        string[] dataTypes,
        uint256 expiryTime,
        string purpose
    );
    
    event ConsentRevoked(
        address indexed patient,
        address indexed provider,
        uint256 timestamp
    );
    
    event ConsentExpired(
        address indexed patient,
        address indexed provider,
        uint256 timestamp
    );
    
    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }
    
    /**
     * @dev Grant consent to a healthcare provider
     */
    function grantConsent(
        address _provider,
        string[] memory _dataTypes,
        uint256 _durationDays,
        string memory _purpose
    ) external onlyRole(PATIENT_ROLE) {
        require(_provider != address(0), "Invalid provider address");
        require(_dataTypes.length > 0, "Must specify data types");
        require(_durationDays > 0 && _durationDays <= 365, "Invalid duration");
        
        uint256 expiryTime = block.timestamp + (_durationDays * 1 days);
        
        // Check if this is a new provider for the patient
        bool isNewProvider = !consents[msg.sender][_provider].isActive;
        
        consents[msg.sender][_provider] = Consent({
            provider: _provider,
            dataTypes: _dataTypes,
            grantedAt: block.timestamp,
            expiryTime: expiryTime,
            isActive: true,
            purpose: _purpose
        });
        
        if (isNewProvider) {
            patientProviders[msg.sender].push(_provider);
        }
        
        auditLog.push(ConsentLog({
            patient: msg.sender,
            provider: _provider,
            action: "granted",
            timestamp: block.timestamp
        }));
        
        emit ConsentGranted(msg.sender, _provider, _dataTypes, expiryTime, _purpose);
    }
    
    /**
     * @dev Revoke consent from a provider
     */
    function revokeConsent(address _provider) 
        external 
        onlyRole(PATIENT_ROLE) 
    {
        require(_provider != address(0), "Invalid provider address");
        require(consents[msg.sender][_provider].isActive, "No active consent");
        
        consents[msg.sender][_provider].isActive = false;
        
        auditLog.push(ConsentLog({
            patient: msg.sender,
            provider: _provider,
            action: "revoked",
            timestamp: block.timestamp
        }));
        
        emit ConsentRevoked(msg.sender, _provider, block.timestamp);
    }
    
    /**
     * @dev Check if provider has valid consent
     */
    function checkConsent(address _patient, address _provider) 
        external 
        view 
        returns (bool hasConsent, string[] memory dataTypes, uint256 expiryTime) 
    {
        Consent memory consent = consents[_patient][_provider];
        
        bool isValid = consent.isActive && block.timestamp < consent.expiryTime;
        
        return (isValid, consent.dataTypes, consent.expiryTime);
    }
    
    /**
     * @dev Check if provider can access specific data type
     */
    function canAccessDataType(
        address _patient,
        address _provider,
        string memory _dataType
    ) external view returns (bool) {
        Consent memory consent = consents[_patient][_provider];
        
        if (!consent.isActive || block.timestamp >= consent.expiryTime) {
            return false;
        }
        
        for (uint i = 0; i < consent.dataTypes.length; i++) {
            if (keccak256(bytes(consent.dataTypes[i])) == keccak256(bytes(_dataType))) {
                return true;
            }
        }
        
        return false;
    }
    
    /**
     * @dev Get all providers with consent from a patient
     */
    function getPatientProviders(address _patient) 
        external 
        view 
        returns (address[] memory) 
    {
        require(
            msg.sender == _patient || 
            hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Unauthorized"
        );
        
        return patientProviders[_patient];
    }
    
    /**
     * @dev Get consent details
     */
    function getConsent(address _patient, address _provider) 
        external 
        view 
        returns (
            string[] memory dataTypes,
            uint256 grantedAt,
            uint256 expiryTime,
            bool isActive,
            string memory purpose
        ) 
    {
        require(
            msg.sender == _patient || 
            msg.sender == _provider ||
            hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Unauthorized"
        );
        
        Consent memory consent = consents[_patient][_provider];
        
        return (
            consent.dataTypes,
            consent.grantedAt,
            consent.expiryTime,
            consent.isActive && block.timestamp < consent.expiryTime,
            consent.purpose
        );
    }
    
    /**
     * @dev Get audit log count
     */
    function getAuditLogCount() external view returns (uint256) {
        return auditLog.length;
    }
    
    /**
     * @dev Get audit log entry
     */
    function getAuditLogEntry(uint256 _index) 
        external 
        view 
        returns (
            address patient,
            address provider,
            string memory action,
            uint256 timestamp
        ) 
    {
        require(_index < auditLog.length, "Invalid index");
        require(hasRole(DEFAULT_ADMIN_ROLE, msg.sender), "Admin only");
        
        ConsentLog memory log = auditLog[_index];
        return (log.patient, log.provider, log.action, log.timestamp);
    }
}

contracts/HealthRecordRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title HealthRecordRegistry
 * @dev Manages immutable health record hashes with access control
 */
contract HealthRecordRegistry is AccessControl, ReentrancyGuard {
    bytes32 public constant DOCTOR_ROLE = keccak256("DOCTOR_ROLE");
    bytes32 public constant PATIENT_ROLE = keccak256("PATIENT_ROLE");
    
    struct HealthRecord {
        bytes32 recordHash;
        string ipfsHash;
        address patient;
        address doctor;
        string recordType;
        uint256 timestamp;
        bool isActive;
    }
    
    struct AccessGrant {
        address provider;
        uint256 expiryTime;
        bool isActive;
    }
    
    // Mapping: recordId => HealthRecord
    mapping(uint256 => HealthRecord) public records;
    
    // Mapping: patient => doctor => AccessGrant
    mapping(address => mapping(address => AccessGrant)) public accessGrants;
    
    // Mapping: patient => recordIds[]
    mapping(address => uint256[]) public patientRecords;
    
    // Mapping: recordHash => recordId
    mapping(bytes32 => uint256) public recordHashToId;
    
    uint256 public recordCount;
    
    event RecordRegistered(
        uint256 indexed recordId,
        bytes32 indexed recordHash,
        address indexed patient,
        address doctor,
        string recordType,
        uint256 timestamp
    );
    
    event AccessGranted(
        address indexed patient,
        address indexed provider,
        uint256 expiryTime
    );
    
    event AccessRevoked(
        address indexed patient,
        address indexed provider
    );
    
    event RecordDeactivated(uint256 indexed recordId);
    
    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }
    
    /**
     * @dev Register a new health record
     */
    function registerRecord(
        bytes32 _recordHash,
        string memory _ipfsHash,
        address _patient,
        string memory _recordType
    ) external onlyRole(DOCTOR_ROLE) nonReentrant returns (uint256) {
        require(_recordHash != bytes32(0), "Invalid record hash");
        require(_patient != address(0), "Invalid patient address");
        require(recordHashToId[_recordHash] == 0, "Record already exists");
        
        recordCount++;
        uint256 recordId = recordCount;
        
        records[recordId] = HealthRecord({
            recordHash: _recordHash,
            ipfsHash: _ipfsHash,
            patient: _patient,
            doctor: msg.sender,
            recordType: _recordType,
            timestamp: block.timestamp,
            isActive: true
        });
        
        recordHashToId[_recordHash] = recordId;
        patientRecords[_patient].push(recordId);
        
        emit RecordRegistered(
            recordId,
            _recordHash,
            _patient,
            msg.sender,
            _recordType,
            block.timestamp
        );
        
        return recordId;
    }
    
    /**
     * @dev Verify a health record exists and is valid
     */
    function verifyRecord(bytes32 _recordHash) 
        external 
        view 
        returns (bool exists, bool isActive, uint256 timestamp) 
    {
        uint256 recordId = recordHashToId[_recordHash];
        if (recordId == 0) {
            return (false, false, 0);
        }
        
        HealthRecord memory record = records[recordId];
        return (true, record.isActive, record.timestamp);
    }
    
    /**
     * @dev Get patient's record history
     */
    function getPatientRecords(address _patient) 
        external 
        view 
        returns (uint256[] memory) 
    {
        require(
            msg.sender == _patient || 
            hasRole(DOCTOR_ROLE, msg.sender) && hasAccess(_patient, msg.sender) ||
            hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Unauthorized access"
        );
        
        return patientRecords[_patient];
    }
    
    /**
     * @dev Grant access to a healthcare provider
     */
    function grantAccess(address _provider, uint256 _duration) 
        external 
        onlyRole(PATIENT_ROLE) 
    {
        require(_provider != address(0), "Invalid provider address");
        require(_duration > 0, "Duration must be positive");
        
        uint256 expiryTime = block.timestamp + _duration;
        
        accessGrants[msg.sender][_provider] = AccessGrant({
            provider: _provider,
            expiryTime: expiryTime,
            isActive: true
        });
        
        emit AccessGranted(msg.sender, _provider, expiryTime);
    }
    
    /**
     * @dev Revoke access from a healthcare provider
     */
    function revokeAccess(address _provider) 
        external 
        onlyRole(PATIENT_ROLE) 
    {
        require(_provider != address(0), "Invalid provider address");
        
        accessGrants[msg.sender][_provider].isActive = false;
        
        emit AccessRevoked(msg.sender, _provider);
    }
    
    /**
     * @dev Check if provider has access to patient data
     */
    function hasAccess(address _patient, address _provider) 
        public 
        view 
        returns (bool) 
    {
        AccessGrant memory grant = accessGrants[_patient][_provider];
        return grant.isActive && block.timestamp < grant.expiryTime;
    }
    
    /**
     * @dev Deactivate a record (soft delete)
     */
    function deactivateRecord(uint256 _recordId) 
        external 
        onlyRole(DOCTOR_ROLE) 
    {
        require(_recordId > 0 && _recordId <= recordCount, "Invalid record ID");
        require(records[_recordId].doctor == msg.sender, "Not record owner");
        
        records[_recordId].isActive = false;
        
        emit RecordDeactivated(_recordId);
    }
    
    /**
     * @dev Get record details
     */
    function getRecord(uint256 _recordId) 
        external 
        view 
        returns (
            bytes32 recordHash,
            string memory ipfsHash,
            address patient,
            address doctor,
            string memory recordType,
            uint256 timestamp,
            bool isActive
        ) 
    {
        require(_recordId > 0 && _recordId <= recordCount, "Invalid record ID");
        HealthRecord memory record = records[_recordId];
        
        require(
            msg.sender == record.patient || 
            msg.sender == record.doctor ||
            hasAccess(record.patient, msg.sender) ||
            hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Unauthorized access"
        );
        
        return (
            record.recordHash,
            record.ipfsHash,
            record.patient,
            record.doctor,
            record.recordType,
            record.timestamp,
            record.isActive
        );
    }
}

contracts/PrescriptionRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title PrescriptionRegistry
 * @dev Manages prescription issuance and verification on blockchain
 */
contract PrescriptionRegistry is AccessControl, ReentrancyGuard {
    bytes32 public constant DOCTOR_ROLE = keccak256("DOCTOR_ROLE");
    bytes32 public constant PHARMACIST_ROLE = keccak256("PHARMACIST_ROLE");
    
    struct Prescription {
        bytes32 prescriptionHash;
        address patient;
        address doctor;
        string ipfsHash;
        uint256 issueDate;
        uint256 validUntil;
        bool isValid;
        bool isFilled;
        address filledBy;
        uint256 filledAt;
    }
    
    mapping(uint256 => Prescription) public prescriptions;
    mapping(bytes32 => uint256) public prescriptionHashToId;
    mapping(address => uint256[]) public patientPrescriptions;
    mapping(address => uint256[]) public doctorPrescriptions;
    
    uint256 public prescriptionCount;
    
    event PrescriptionIssued(
        uint256 indexed prescriptionId,
        bytes32 indexed prescriptionHash,
        address indexed patient,
        address doctor,
        uint256 issueDate,
        uint256 validUntil
    );
    
    event PrescriptionFilled(
        uint256 indexed prescriptionId,
        address indexed pharmacist,
        uint256 filledAt
    );
    
    event PrescriptionInvalidated(
        uint256 indexed prescriptionId,
        address indexed invalidatedBy
    );
    
    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }
    
    /**
     * @dev Issue a new prescription
     */
    function issuePrescription(
        bytes32 _prescriptionHash,
        address _patient,
        string memory _ipfsHash,
        uint256 _validityDays
    ) external onlyRole(DOCTOR_ROLE) nonReentrant returns (uint256) {
        require(_prescriptionHash != bytes32(0), "Invalid prescription hash");
        require(_patient != address(0), "Invalid patient address");
        require(_validityDays > 0 && _validityDays <= 365, "Invalid validity period");
        require(prescriptionHashToId[_prescriptionHash] == 0, "Prescription already exists");
        
        prescriptionCount++;
        uint256 prescriptionId = prescriptionCount;
        
        uint256 issueDate = block.timestamp;
        uint256 validUntil = issueDate + (_validityDays * 1 days);
        
        prescriptions[prescriptionId] = Prescription({
            prescriptionHash: _prescriptionHash,
            patient: _patient,
            doctor: msg.sender,
            ipfsHash: _ipfsHash,
            issueDate: issueDate,
            validUntil: validUntil,
            isValid: true,
            isFilled: false,
            filledBy: address(0),
            filledAt: 0
        });
        
        prescriptionHashToId[_prescriptionHash] = prescriptionId;
        patientPrescriptions[_patient].push(prescriptionId);
        doctorPrescriptions[msg.sender].push(prescriptionId);
        
        emit PrescriptionIssued(
            prescriptionId,
            _prescriptionHash,
            _patient,
            msg.sender,
            issueDate,
            validUntil
        );
        
        return prescriptionId;
    }
    
    /**
     * @dev Verify prescription validity
     */
    function verifyPrescription(bytes32 _prescriptionHash) 
        external 
        view 
        returns (
            bool exists,
            bool isValid,
            bool isExpired,
            bool isFilled,
            address doctor,
            address patient
        ) 
    {
        uint256 prescriptionId = prescriptionHashToId[_prescriptionHash];
        
        if (prescriptionId == 0) {
            return (false, false, false, false, address(0), address(0));
        }
        
        Prescription memory prescription = prescriptions[prescriptionId];
        bool expired = block.timestamp > prescription.validUntil;
        
        return (
            true,
            prescription.isValid,
            expired,
            prescription.isFilled,
            prescription.doctor,
            prescription.patient
        );
    }
    
    /**
     * @dev Fill a prescription (pharmacist action)
     */
    function fillPrescription(uint256 _prescriptionId) 
        external 
        onlyRole(PHARMACIST_ROLE) 
        nonReentrant 
    {
        require(_prescriptionId > 0 && _prescriptionId <= prescriptionCount, "Invalid prescription ID");
        
        Prescription storage prescription = prescriptions[_prescriptionId];
        
        require(prescription.isValid, "Prescription is not valid");
        require(!prescription.isFilled, "Prescription already filled");
        require(block.timestamp <= prescription.validUntil, "Prescription expired");
        
        prescription.isFilled = true;
        prescription.filledBy = msg.sender;
        prescription.filledAt = block.timestamp;
        
        emit PrescriptionFilled(_prescriptionId, msg.sender, block.timestamp);
    }
    
    /**
     * @dev Invalidate a prescription
     */
    function invalidatePrescription(uint256 _prescriptionId) 
        external 
        nonReentrant 
    {
        require(_prescriptionId > 0 && _prescriptionId <= prescriptionCount, "Invalid prescription ID");
        
        Prescription storage prescription = prescriptions[_prescriptionId];
        
        require(
            msg.sender == prescription.doctor || 
            hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Unauthorized"
        );
        
        require(prescription.isValid, "Prescription already invalid");
        
        prescription.isValid = false;
        
        emit PrescriptionInvalidated(_prescriptionId, msg.sender);
    }
    
    /**
     * @dev Get patient's prescriptions
     */
    function getPatientPrescriptions(address _patient) 
        external 
        view 
        returns (uint256[] memory) 
    {
        require(
            msg.sender == _patient || 
            hasRole(DOCTOR_ROLE, msg.sender) ||
            hasRole(PHARMACIST_ROLE, msg.sender) ||
            hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Unauthorized"
        );
        
        return patientPrescriptions[_patient];
    }
    
    /**
     * @dev Get doctor's prescriptions
     */
    function getDoctorPrescriptions(address _doctor) 
        external 
        view 
        returns (uint256[] memory) 
    {
        require(
            msg.sender == _doctor || 
            hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Unauthorized"
        );
        
        return doctorPrescriptions[_doctor];
    }
    
    /**
     * @dev Get prescription details
     */
    function getPrescription(uint256 _prescriptionId) 
        external 
        view 
        returns (
            bytes32 prescriptionHash,
            address patient,
            address doctor,
            string memory ipfsHash,
            uint256 issueDate,
            uint256 validUntil,
            bool isValid,
            bool isFilled
        ) 
    {
        require(_prescriptionId > 0 && _prescriptionId <= prescriptionCount, "Invalid prescription ID");
        
        Prescription memory prescription = prescriptions[_prescriptionId];
        
        require(
            msg.sender == prescription.patient || 
            msg.sender == prescription.doctor ||
            hasRole(PHARMACIST_ROLE, msg.sender) ||
            hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Unauthorized"
        );
        
        return (
            prescription.prescriptionHash,
            prescription.patient,
            prescription.doctor,
            prescription.ipfsHash,
            prescription.issueDate,
            prescription.validUntil,
            prescription.isValid,
            prescription.isFilled
        );
    }
}

